pub fn my_split_at_mut<T>(slice: &mut [T], mid: usize) -> (&mut [T], &mut [T]) {
    let len = slice.len();

    if mid > len {
        panic!("mid ({}) is out of bounds for slice of length {}", mid, len);
    }

    unsafe {
        let ptr = slice.as_mut_ptr();
        let left_len = mid;
        let right_len = len - mid;

        // Create two mutable slices from the same pointer, but with disjoint ranges
        let left = std::slice::from_raw_parts_mut(ptr, left_len);
        let right = std::slice::from_raw_parts_mut(ptr.add(mid), right_len);

        (left, right)
    }
}

